bool is_bipartite_graph(int n, const vector<vector<int>>& g) {
	var color = vector<short>(n + 1, -1);

	auto bfs_check = [&](int st)->bool {
		queue<int> q;
		q.push(st);
		color[st] = 0;

		while (!q.empty()) {
			int u = q.front();
			q.pop();

			for (int v : g[u]) {
				if (color[v] == -1) {
					color[v] = color[u] ^ 1;
					q.push(v);
				}
				else if (color[v] == color[u]) {
					return false;
				}
			}
		}
		return true;
		};

	fa(i, 1, n)
		if (color[i] == -1 and !bfs_check(i))
			return false;

	return true;
}
